def _cleanup_old_screenshots(max_age_hours: int = 24):
    """静默清理过期调试截图，不影响启动。"""
    import time
    from pathlib import Path

    project_root = Path(__file__).parent.parent
    dirs = [
        project_root / "screenshots_debug",
        project_root / "chat_agent_data" / "screenshots",
    ]

    now = time.time()
    for d in dirs:
        if not d.exists():
            continue
        for f in d.glob("*.png"):
            try:
                if (now - f.stat().st_mtime) > max_age_hours * 3600:
                    f.unlink()
            except Exception:
                pass

def _parse_region(s: str) -> tuple[int, int, int, int]:
    """解析区域字符串 "x,y,w,h" 。"""
    parts = s.split(",")
    if len(parts) != 4:
        raise argparse.ArgumentTypeError(f"区域格式错误，应为 x,y,width,height: {s!r}")
    return tuple(int(p.strip()) for p in parts)

def cmd_screenshot(args):
    """截图命令。"""
    from .core.screen import screenshot, screenshot_window, get_screen_info
    from .core.window import find_window
    from pathlib import Path

    # 如果 --save 是裸文件名（无目录），自动放到 screenshots_debug/
    if args.save and os.path.dirname(args.save) == "":
        debug_dir = Path(__file__).parent.parent / "screenshots_debug"
        debug_dir.mkdir(exist_ok=True)
        args.save = str(debug_dir / args.save)

    region = None

    if args.region:
        region = _parse_region(args.region)
    elif args.window:
        hwnd = find_window(args.window)
        if not hwnd:
            print(json.dumps({"error": f"未找到窗口: {args.window!r}"}, ensure_ascii=False))
            return 1
        # 截窗口
        data = screenshot_window(hwnd, save_path=args.save, quality=args.quality, format=args.format)
        if args.save:
            result = {"success": True, "path": os.path.abspath(args.save), "size": len(data)}
            print(json.dumps(result, ensure_ascii=False))
        elif args.base64:
            import base64
            print(base64.b64encode(data).decode("ascii"))
        else:
            sys.stdout.buffer.write(data)
        return 0

    data = screenshot(region=region, save_path=args.save, quality=args.quality, format=args.format)

    if args.save:
        result = {"success": True, "path": os.path.abspath(args.save), "size": len(data)}
        print(json.dumps(result, ensure_ascii=False))
    elif args.base64:
        import base64
        print(base64.b64encode(data).decode("ascii"))
    else:
        # 二进制输出到 stdout
        sys.stdout.buffer.write(data)

    return 0

def main():
    """CLI 入口。"""
    parser = build_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        return 0

    try:
        return args.func(args)
    except KeyboardInterrupt:
        return 130
    except Exception as e:
        error = {"error": str(e), "type": type(e).__name__}
        print(json.dumps(error, ensure_ascii=False), file=sys.stderr)
        return 1

# ─── 工具函数 ──────────────────────────────────────────────

def _ensure_dirs():
    """确保数据目录存在。"""
    for d in [DATA_DIR, LOG_DIR, SCREENSHOT_DIR, HISTORY_DIR]:
        d.mkdir(parents=True, exist_ok=True)

def _is_ascii(text: str) -> bool:
    """判断文本是否全为 ASCII 字符。"""
    return all(ord(c) < 128 for c in text)

def image_to_base64(path: str) -> str:
    """图片转 Base64。"""
    with open(path, "rb") as f:
        return base64.b64encode(f.read()).decode("ascii")

def image_hash(path: str) -> str:
    """计算图片文件的 SHA256 哈希（用于快速比对画面变化）。"""
    with open(path, "rb") as f:
        return hashlib.sha256(f.read()).hexdigest()

def load_style_profile(style_path: Path | None = None) -> dict:
    """加载风格配置。"""
    path = style_path or STYLE_FILE
    if not path.exists():
        return {}
    try:
        import yaml
        with open(path, "r", encoding="utf-8") as f:
            data = yaml.safe_load(f)
            return data.get("style_profile", data) if data else {}
    except ImportError:
        # 没有 pyyaml，尝试 JSON 格式
        try:
            with open(path, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            return {}
    except Exception:
        return {}

# ─── 截图 ──────────────────────────────────────────────────

def screenshot_chat(save_path: str) -> bool:
    """截图微信聊天窗口。"""
    from .core.screen import screenshot
    from .core.window import focus_window

    result = focus_window("微信")
    if not result.get("success"):
        return False

    try:
        region = (result["x"], result["y"], result["width"], result["height"])
        data = screenshot(region=region, save_path=save_path)
        return bool(data)
    except Exception as e:
        print(f"  ❌ 截图失败: {e}", file=sys.stderr)
        return False

# ─── AI 视觉分析 ───────────────────────────────────────────

def analyze_screenshot(
    image_path: str,
    style_profile: dict,
    contact: str,
    api_key: str,
) -> dict:
    """用 AI 视觉 API 分析聊天截图。

    返回:
        {
            "has_new_message": bool,
            "last_message_from": "contact" | "me",
            "last_message_text": str,
            "suggested_reply": str | None,
            "confidence": float
        }
    """
    try:
        from openai import OpenAI
    except ImportError:
        print("  ❌ 需要 openai 库: pip install openai", file=sys.stderr)
        return {"has_new_message": False, "confidence": 0}

    client = OpenAI(api_key=api_key)
    b64_image = image_to_base64(image_path)

    # 构建风格提示
    style_prompt = ""
    if style_profile:
        style_prompt = f"""
你需要模仿用户的聊天风格来回复。用户的风格特征：
- 语气：{style_profile.get('tone', '随意')}
- 句子长度：{style_profile.get('sentence_length', '短')}
- 口头禅：{', '.join(style_profile.get('filler_words', []))}
- 标点习惯：{style_profile.get('punctuation_style', '正常')}
- Emoji 使用：{style_profile.get('emoji_usage', '适中')}
- 标志性用语：{', '.join(style_profile.get('signature_phrases', []))}

示例对话：
"""
        for ex in style_profile.get("example_exchanges", [])[:5]:
            style_prompt += f"  对方：{ex.get('received', '')}\n"
            style_prompt += f"  用户回复：{ex.get('replied', '')}\n"

    messages = [
        {
            "role": "system",
            "content": f"""你是一个聊天截图分析助手。分析微信聊天截图并返回 JSON。

任务：
1. 识别截图中的聊天内容
2. 判断最新一条消息是对方发的还是用户发的
3. 如果最新消息来自对方（联系人：{contact}），生成一条合适的回复

{style_prompt}

严格返回以下 JSON 格式（不要加 markdown 标记）：
{{
    "has_new_message": true/false,
    "last_message_from": "contact" 或 "me",
    "last_message_text": "最新消息的内容",
    "suggested_reply": "建议的回复内容（仅当需要回复时）",
    "confidence": 0.0-1.0
}}

如果无法识别内容，设 confidence 为 0 且 has_new_message 为 false。
不要回复涉及金钱、密码、隐私的消息，此时 suggested_reply 设为 null。"""
        },
        {
            "role": "user",
            "content": [
                {"type": "text", "text": f"分析这张微信聊天截图。联系人是 {contact}。"},
                {
                    "type": "image_url",
                    "image_url": {
                        "url": f"data:image/png;base64,{b64_image}",
                        "detail": "high",
                    },
                },
            ],
        },
    ]

    response = client.chat.completions.create(
        model="gpt-4o",
        messages=messages,
        max_tokens=500,
        temperature=0.7,
    )

    reply_text = response.choices[0].message.content.strip()

    # 清理可能的 markdown 包裹
    if reply_text.startswith("```"):
        reply_text = reply_text.split("\n", 1)[1]
        reply_text = reply_text.rsplit("```", 1)[0]

    try:
        return json.loads(reply_text)
    except json.JSONDecodeError:
        print(f"  ⚠️ AI 返回解析失败: {reply_text[:200]}", file=sys.stderr)
        return {"has_new_message": False, "confidence": 0}

def init_dpi():
    """进程启动时调用一次，声明 Per-Monitor DPI Awareness。

    必须在任何 GUI / 截图库导入前调用。
    """
    global _initialized
    if _initialized:
        return
    try:
        # Per-Monitor DPI Aware V2 (Windows 10 1703+)
        ctypes.windll.shcore.SetProcessDpiAwareness(2)
    except Exception:
        try:
            # 回退到 System DPI Aware
            ctypes.windll.user32.SetProcessDPIAware()
        except Exception:
            pass
    _initialized = True

def get_clipboard_text() -> str:
    """从系统剪贴板读取文本。

    Returns:
        剪贴板文本，失败返回空字符串
    """
    try:
        if not ctypes.windll.user32.OpenClipboard(0):
            return ""

        try:
            h_data = ctypes.windll.user32.GetClipboardData(CF_UNICODETEXT)
            if not h_data:
                return ""

            p_data = ctypes.windll.kernel32.GlobalLock(h_data)
            if not p_data:
                return ""

            try:
                text = ctypes.wstring_at(p_data)
                return text
            finally:
                ctypes.windll.kernel32.GlobalUnlock(h_data)
        finally:
            ctypes.windll.user32.CloseClipboard()
    except Exception:
        return ""

windows = []

def callback(hwnd, _):
    if include_all:
        if not ctypes.windll.user32.IsWindowVisible(hwnd):
            return True
        title = _get_window_title(hwnd)
        if not title:
            return True
    else:
        if not _is_real_window(hwnd):
            return True
        title = _get_window_title(hwnd)

    x, y, w, h = _get_window_rect(hwnd)
    windows.append({
        "hwnd": hwnd,
        "title": title,
        "class": _get_class_name(hwnd),
        "pid": _get_process_id(hwnd),
        "x": x, "y": y,
        "width": w, "height": h,
    })
    return True

ctypes.windll.user32.EnumWindows(WNDENUMPROC(callback), 0)

def find_window(title: str, exact: bool = False) -> Optional[int]:
    """按标题查找窗口。

    Args:
        title: 窗口标题（支持部分匹配和正则）
        exact: True = 精确匹配，False = 包含匹配

    Returns:
        窗口句柄 hwnd，未找到返回 None
    """
    if exact:
        hwnd = ctypes.windll.user32.FindWindowW(None, title)
        return hwnd if hwnd else None

    # 模糊匹配 + 正则匹配（只枚举一次）
    title_lower = title.lower()
    all_windows = list_windows(include_all=True)

    for win in all_windows:
        if title_lower in win["title"].lower():
            return win["hwnd"]

    # 正则匹配
    try:
        pattern = re.compile(title, re.IGNORECASE)
        for win in all_windows:
            if pattern.search(win["title"]):
                return win["hwnd"]
    except re.error:
        pass

    return None

def move_window(title: str, x: int, y: int, width: int = 0, height: int = 0) -> dict:
    """移动/调整窗口大小。

    Args:
        title: 窗口标题
        x, y: 新位置
        width, height: 新尺寸（0 = 保持不变）
    """
    hwnd = find_window(title)
    if not hwnd:
        return {"success": False, "error": f"未找到窗口: {title!r}"}

    if width == 0 or height == 0:
        _, _, cur_w, cur_h = _get_window_rect(hwnd)
        if width == 0:
            width = cur_w
        if height == 0:
            height = cur_h

    ctypes.windll.user32.MoveWindow(hwnd, x, y, width, height, True)

    return {
        "success": True,
        "hwnd": hwnd,
        "x": x, "y": y,
        "width": width, "height": height,
    }

def minimize_window(title: str) -> dict:
    """最小化窗口。"""
    hwnd = find_window(title)
    if not hwnd:
        return {"success": False, "error": f"未找到窗口: {title!r}"}
    ctypes.windll.user32.ShowWindow(hwnd, SW_MINIMIZE)
    return {"success": True, "hwnd": hwnd}

def maximize_window(title: str) -> dict:
    """最大化窗口。"""
    hwnd = find_window(title)
    if not hwnd:
        return {"success": False, "error": f"未找到窗口: {title!r}"}
    ctypes.windll.user32.ShowWindow(hwnd, SW_MAXIMIZE)
    return {"success": True, "hwnd": hwnd}

def get_foreground_window() -> dict:
    """获取当前前台窗口信息。"""
    hwnd = ctypes.windll.user32.GetForegroundWindow()
    if not hwnd:
        return {"success": False, "error": "无前台窗口"}

    title = _get_window_title(hwnd)
    x, y, w, h = _get_window_rect(hwnd)

    return {
        "success": True,
        "hwnd": hwnd,
        "title": title,
        "class": _get_class_name(hwnd),
        "x": x, "y": y,
        "width": w, "height": h,
    }

    ]

def _get_vk(key: str) -> int:
    """将按键名转换为 Virtual Key Code。"""
    key_lower = key.lower().strip()

    # 查表
    if key_lower in VK_MAP:
        return VK_MAP[key_lower]

    # 单字符 → VkKeyScan
    if len(key) == 1:
        vk = ctypes.windll.user32.VkKeyScanW(ord(key))
        if vk != -1:
            return vk & 0xFF

    raise ValueError(f"未知按键: {key!r}")

def type_text(text: str, use_clipboard: bool = True, interval: float = 0):
    """输入文本。

    Args:
        text: 要输入的文本（支持中文）
        use_clipboard: True = 通过剪贴板粘贴（支持中文），False = 逐字符按键（仅 ASCII）
        interval: 逐字符模式的按键间隔
    """
    if use_clipboard:
        # 剪贴板方式：支持任意字符（中文、emoji 等）
        set_clipboard_text(text)
        time.sleep(0.05)
        hotkey("ctrl", "v")
        time.sleep(0.05)
    else:
        # 逐字符方式：仅支持 ASCII
        for ch in text:
            try:
                vk_result = ctypes.windll.user32.VkKeyScanW(ord(ch))
                if vk_result == -1:
                    continue
                vk = vk_result & 0xFF
                shift = bool(vk_result & 0x100)

                if shift:
                    ctypes.windll.user32.keybd_event(0x10, 0, 0, 0)  # SHIFT down

                ctypes.windll.user32.keybd_event(vk, 0, 0, 0)
                time.sleep(0.01)
                ctypes.windll.user32.keybd_event(vk, 0, KEYEVENTF_KEYUP, 0)

                if shift:
                    ctypes.windll.user32.keybd_event(0x10, 0, KEYEVENTF_KEYUP, 0)

                if interval > 0:
                    time.sleep(interval)
            except Exception:
                continue
